import React, { useState, useEffect, useMemo, useCallback, useRef } from 'react';
import { Container, Card, Stack, Row, Box, Divider, Spacer, Text, Heading, Button, Input, TextArea, Select, Checkbox, Toggle, RadioGroup, Slider, Badge, Spinner, Avatar, Alert, Progress, Image, Icon, Link, Tooltip, Table, Tabs, Toast, Accordion } from '@ggui-ai/design/primitives';
import { SearchField, FormField, MenuItem, Tag, Dropdown, Autocomplete, Breadcrumb, Pagination } from '@ggui-ai/design/components';
import { Header, Sidebar, CardGrid, CommentThread, DataTable, ChatWindow, NavigationBar, FileUploader, UserProfileCard, NotificationCenter, Modal, CommandPalette, Footer, Hero } from '@ggui-ai/design/compositions';
import { Clickable, Hoverable, Pressable } from '@ggui-ai/design/interact';

// ⚠️ DO NOT EDIT — generated from data contract. Changing this will fail validation.
interface Props {
  city: string; // City name
  temperature: number; // Current temperature
  condition: string; // Weather condition (Sunny, Cloudy, Rainy, etc.)
  humidity: number; // Humidity percentage
  windSpeed: number; // Wind speed
  unit: string; // Temperature unit (C or F)
  forecast: { day: string; icon: string; high: number; low: number }[]; // 5-day forecast array
}

function useComponent(props: Props) {
  const weatherIcons: Record<string, string> = {
    sunny: 'sun',
    cloudy: 'cloud',
    rainy: 'cloud-rain',
    snowy: 'snowflake',
    windy: 'wind'
  };

  const getIcon = useCallback((condition: string) =>
    weatherIcons[condition.toLowerCase()] || 'info', [weatherIcons]);

  return { getIcon };
}

export default function Component(props: Props) {
  const { getIcon } = useComponent(props);

  return (
    <Card padding={24} style={{ maxWidth: '400px' }}>
      <Stack gap={16}>
        <Row justify="between" align="center" style={{ width: '100%' }}>
          <Heading level={2}>{props.city}</Heading>
          <Badge variant="primary" pill>{props.condition}</Badge>
        </Row>
        <Stack align="center" gap={8} style={{ padding: 'var(--ggui-spacing-4, 16px) 0' }}>
          <Icon name={getIcon(props.condition)} size={72} color="var(--ggui-color-primary-600, #0284c7)" />
          <Text size="4xl" weight="bold">{Math.round(props.temperature)}°{props.unit}</Text>
        </Stack>
        <Row justify="center" gap={32}>
          <Stack align="center" gap={4}><Text variant="caption" color="var(--ggui-color-onSurfaceVariant)">Humidity</Text><Text weight="semibold">{props.humidity}%</Text></Stack>
          <Stack align="center" gap={4}><Text variant="caption" color="var(--ggui-color-onSurfaceVariant)">Wind</Text><Text weight="semibold">{props.windSpeed} km/h</Text></Stack>
        </Row>
        <Divider />
        <Row justify="between">
          {props.forecast.map((f, i) => (
            <Box as={Hoverable} key={i} padding={8} borderRadius="md" hoverStyle={{ background: 'var(--ggui-color-surfaceVariant)' }}>
              <Stack align="center" gap={4}>
                <Text variant="overline">{f.day}</Text>
                <Icon name={getIcon(f.icon)} size={20} />
                <Text variant="bodySmall" weight="bold">{f.high}°</Text>
                <Text variant="caption" color="var(--ggui-color-onSurfaceVariant)">{f.low}°</Text>
              </Stack>
            </Box>
          ))}
        </Row>
      </Stack>
    </Card>
  );
}

