import React, { useState, useEffect, useMemo, useCallback, useRef } from 'react';
import { Container, Card, Stack, Row, Box, Divider, Spacer, Text, Heading, Button, Input, TextArea, Select, Checkbox, Toggle, RadioGroup, Slider, Badge, Spinner, Avatar, Alert, Progress, Image, Icon, Link, Tooltip, Table, Tabs, Toast, Accordion } from '@ggui-ai/design/primitives';
import { SearchField, FormField, MenuItem, Tag, Dropdown, Autocomplete, Breadcrumb, Pagination } from '@ggui-ai/design/components';
import { Header, Sidebar, CardGrid, CommentThread, DataTable, ChatWindow, NavigationBar, FileUploader, UserProfileCard, NotificationCenter, Modal, CommandPalette, Footer, Hero } from '@ggui-ai/design/compositions';
import { Clickable, Hoverable, Pressable } from '@ggui-ai/design/interact';

// ⚠️ DO NOT EDIT — generated from data contract. Changing this will fail validation.
interface Props {
  tasks: { id: string; title: string; priority: string; assignee: string; column: string; dueDate: string }[]; // Array of tasks with id, title, priority (low/medium/high), assignee initials, column ID, and optional dueDate
  columns: Array<{ id?: string; name?: string }>; // Column definitions: [{id: "todo", name: "To Do"}, {id: "in-progress", name: "In Progress"}, {id: "done", name: "Done"}]
  onTaskUpdate?: (data: Record<string, unknown>) => void; // Action: Task Updated
}

function useComponent(props: Props) {
  const handleTaskUpdate = useCallback((data: Record<string, unknown>) => {
    props.onTaskUpdate?.(data);
  }, [props.onTaskUpdate]);

  const [tasks, setTasks] = useState(props.tasks);
  const [addingTo, setAddingTo] = useState<string | null>(null);
  const [newTaskTitle, setNewTaskTitle] = useState('');
  const [newTaskPriority, setNewTaskPriority] = useState('medium');
  const [editingTaskId, setEditingTaskId] = useState<string | null>(null);
  const [editTaskTitle, setEditTaskTitle] = useState('');
  const [editTaskPriority, setEditTaskPriority] = useState('medium');

  const columns = useMemo(() => props.columns.map(col => ({
    ...col,
    tasks: tasks.filter(t => t.column === col.id),
    id: col.id || ''
  })), [props.columns, tasks]);

  const editTask = useCallback((taskId: string) => {
    const updatedTasks = tasks.map(t => t.id === taskId ? { ...t, title: editTaskTitle, priority: editTaskPriority } : t);
    setTasks(updatedTasks);
    setEditingTaskId(null);
    handleTaskUpdate({ type: 'EDIT', taskId, title: editTaskTitle, priority: editTaskPriority });
  }, [tasks, editTaskTitle, editTaskPriority, handleTaskUpdate]);

  const moveTask = useCallback((taskId: string, targetColumn: string) => {
    const updatedTasks = tasks.map(t => t.id === taskId ? { ...t, column: targetColumn } : t);
    setTasks(updatedTasks);
    handleTaskUpdate({ type: 'MOVE', taskId, targetColumn });
  }, [tasks, handleTaskUpdate]);

  const addTask = useCallback((columnId: string) => {
    if (!newTaskTitle.trim()) return;
    const newTask = {
      id: Date.now().toString(),
      title: newTaskTitle,
      priority: newTaskPriority,
      assignee: '??',
      column: columnId,
      dueDate: ''
    };
    setTasks([...tasks, newTask]);
    setNewTaskTitle('');
    setAddingTo(null);
    handleTaskUpdate({ type: 'CREATE', task: newTask });
  }, [tasks, newTaskTitle, newTaskPriority, handleTaskUpdate]);

  return { columns, addingTo, setAddingTo, newTaskTitle, setNewTaskTitle, newTaskPriority, setNewTaskPriority, moveTask, addTask, editingTaskId, setEditingTaskId, editTaskTitle, setEditTaskTitle, editTaskPriority, setEditTaskPriority, editTask };
}

export default function Component(props: Props) {
  const { columns, addingTo, setAddingTo, newTaskTitle, setNewTaskTitle, newTaskPriority, setNewTaskPriority, moveTask, addTask, editingTaskId, setEditingTaskId, editTaskTitle, setEditTaskTitle, editTaskPriority, setEditTaskPriority, editTask } = useComponent(props);

  const totalTasks = columns.reduce((acc, col) => acc + col.tasks.length, 0);
  const doneTasks = columns.find(c => c.id.toLowerCase() === 'done')?.tasks.length || 0;

  return (
    <Container maxWidth="xl" padding={24}>
      <Stack gap={24}>
        <Row justify="between" align="center">
          <Heading level={1}>Kanban Board</Heading>
          <Row gap={16}>
            <Box background="var(--ggui-color-surfaceVariant, #f4f4f5)" paddingX={16} paddingY={8} borderRadius={8}>
              <Text variant="label">Total Tasks: <strong>{totalTasks}</strong></Text>
            </Box>
            <Box background="var(--ggui-color-success-100, #dcfce7)" paddingX={16} paddingY={8} borderRadius={8}>
              <Text variant="label" color="var(--ggui-color-success-700, #15803d)">Completed: <strong>{doneTasks}</strong></Text>
            </Box>
          </Row>
        </Row>
        <Row gap={16} align="start">
          {columns.map(col => (
            <Box key={col.id} background="var(--ggui-color-surfaceVariant, #f4f4f5)" borderRadius={12} padding={16} style={{ flex: 1, minHeight: 400 }}>
              <Stack gap={16}>
                <Heading level={4}>{col.name} <Badge>{col.tasks.length}</Badge></Heading>
                <Stack gap={8}>
                  {col.tasks.map(task => (
                    <Card key={task.id} padding={12} shadow="sm">
                      <Stack gap={8}>
                        {editingTaskId === task.id ? (
                          <Stack gap={8} background="var(--ggui-color-surfaceVariant)" padding={8} borderRadius={8}>
                            <Input label="Edit Title" value={editTaskTitle} onChange={setEditTaskTitle} size="sm" />
                            <Select label="Priority" value={editTaskPriority} onChange={setEditTaskPriority} options={[{value:'low',label:'Low'},{value:'medium',label:'Medium'},{value:'high',label:'High'}]} size="sm" />
                            <Row gap={8}>
                              <Button size="xs" onClick={() => editTask(task.id)}>Save</Button>
                              <Button size="xs" variant="ghost" onClick={() => setEditingTaskId(null)}>Cancel</Button>
                            </Row>
                          </Stack>
                        ) : (
                          <>
                            <Box as={Clickable} onDoubleClick={() => { setEditingTaskId(task.id); setEditTaskTitle(task.title); setEditTaskPriority(task.priority); }}>
                              <Text variant="body" style={{ fontWeight: 600 }}>{task.title}</Text>
                            </Box>
                            <Row justify="between" align="center">
                              <Badge variant={task.priority === 'high' ? 'error' : task.priority === 'medium' ? 'warning' : 'default'} size="sm">{task.priority}</Badge>
                            </Row>
                            <Row justify="between" align="center">
                              <Text variant="caption" color="var(--ggui-color-onSurfaceVariant, #52525b)">{task.dueDate || 'No date'}</Text>
                              <Avatar name={task.assignee} size={24} />
                            </Row>
                            <Dropdown 
                              trigger={<Button size="xs" variant="outline" fullWidth>Move Task</Button>}
                              options={props.columns.filter(c => c.id !== col.id).map(c => ({ value: c.id || '', label: c.name || '' }))}
                              onChange={(target) => moveTask(task.id, target)}
                            />
                          </>
                        )}
                      </Stack>
                    </Card>
                  ))}
                </Stack>
                {addingTo === col.id ? (
                  <Stack gap={8} background="var(--ggui-color-surface)" padding={12} borderRadius={8}>
                    <Input label="Task Title" value={newTaskTitle} onChange={setNewTaskTitle} placeholder="e.g. Design homepage" size="sm" />
                    <Select label="Priority" value={newTaskPriority} onChange={setNewTaskPriority} options={[{value:'low',label:'Low'},{value:'medium',label:'Medium'},{value:'high',label:'High'}]} size="sm" />
                    <Row gap={8}>
                      <Button size="xs" onClick={() => addTask(col.id)}>Add</Button>
                      <Button size="xs" variant="ghost" onClick={() => setAddingTo(null)}>Cancel</Button>
                    </Row>
                  </Stack>
                ) : (
                  <Button variant="ghost" onClick={() => setAddingTo(col.id)}>+ Add Task</Button>
                )}
              </Stack>
            </Box>
          ))}
        </Row>
      </Stack>
    </Container>
  );
}

