import React, { useState, useEffect, useMemo, useCallback, useRef } from 'react';
import { Container, Card, Stack, Row, Box, Divider, Spacer, Text, Heading, Button, Input, TextArea, Select, Checkbox, Toggle, RadioGroup, Slider, Badge, Spinner, Avatar, Alert, Progress, Image, Icon, Link, Tooltip, Table, Tabs, Toast, Accordion } from '@ggui-ai/design/primitives';
import { SearchField, FormField, MenuItem, Tag, Dropdown, Autocomplete, Breadcrumb, Pagination } from '@ggui-ai/design/components';
import { Header, Sidebar, CardGrid, CommentThread, DataTable, ChatWindow, NavigationBar, FileUploader, UserProfileCard, NotificationCenter, Modal, CommandPalette, Footer, Hero } from '@ggui-ai/design/compositions';
import { Clickable, Hoverable, Pressable } from '@ggui-ai/design/interact';

// ⚠️ DO NOT EDIT — generated from data contract. Changing this will fail validation.
interface Props {
  elements: { atomicNumber: number; symbol: string; name: string; atomicWeight: number; category: string; row: number; col: number }[]; // Full periodic table element data
}

function useComponent(props: Props) {
  const [searchTerm, setSearchTerm] = useState('');
  const [selectedElement, setSelectedElement] = useState<Props['elements'][0] | null>(null);

  const categories = useMemo(() => Array.from(new Set(props.elements.map(e => e.category))), [props.elements]);
  const filteredElements = useMemo(() => 
    props.elements.filter(e => e.name.toLowerCase().includes(searchTerm.toLowerCase()) || e.symbol.toLowerCase().includes(searchTerm.toLowerCase())),
    [props.elements, searchTerm]
  );

  return { searchTerm, setSearchTerm, selectedElement, setSelectedElement, categories, filteredElements };
}

export default function Component(props: Props) {
  const { searchTerm, setSearchTerm, selectedElement, setSelectedElement, categories, filteredElements } = useComponent(props);

  const getCategoryColor = (category: string) => {
    const categoryMap: Record<string, string> = {
      'Alkali Metal': 'var(--ggui-color-primary-400)',
      'Alkaline Earth Metal': 'var(--ggui-color-primary-300)',
      'Transition Metal': 'var(--ggui-color-primary-200)',
      'Post-transition Metal': 'var(--ggui-color-primary-100)',
      'Metalloid': 'var(--ggui-color-info-200)',
      'Reactive Nonmetal': 'var(--ggui-color-success-200)',
      'Noble Gas': 'var(--ggui-color-success-300)',
      'Lanthanide': 'var(--ggui-color-warning-200)',
      'Actinide': 'var(--ggui-color-warning-300)',
      'Halogen': 'var(--ggui-color-error-200)',
    };
    return categoryMap[category] || 'var(--ggui-color-surfaceVariant)';
  };

  return (
    <Container maxWidth="3xl" padding={24}>
      <Stack gap={24}>
        <Heading level={2}>Periodic Table</Heading>
        <SearchField value={searchTerm} onChange={setSearchTerm} placeholder="Search by name or symbol..." />

        <Box paddingY={16}>
          <Text variant="label" style={{ marginBottom: 'var(--ggui-spacing-2)', display: 'block' }}>Legend:</Text>
          <Row gap={16} wrap>
            {categories.map(cat => (
              <Row key={cat} gap={8} align="center">
                <Box style={{ width: '16px', height: '16px', borderRadius: '4px', backgroundColor: getCategoryColor(cat), border: '1px solid var(--ggui-color-outline)' }} />
                <Text variant="bodySmall">{cat}</Text>
              </Row>
            ))}
          </Row>
        </Box>

        <Box style={{ 
          display: 'grid', 
          gridTemplateColumns: 'repeat(18, minmax(0, 1fr))', 
          gap: 'var(--ggui-spacing-1)', 
          minHeight: '500px',
          overflowX: 'auto' 
        }}>
          {props.elements.map(el => {
            const isVisible = filteredElements.includes(el);
            return (
              <Card 
                key={el.symbol} 
                as={Clickable}
                onClick={() => setSelectedElement(el)}
                style={{ 
                  gridRow: `${el.row} / span 1`,
                  gridColumn: `${el.col} / span 1`,
                  opacity: isVisible ? 1 : 0.1,
                  background: getCategoryColor(el.category),
                  height: '60px',
                  transition: 'transform 0.1s, opacity 0.2s, box-shadow 0.2s',
                  border: selectedElement?.atomicNumber === el.atomicNumber 
                    ? '2px solid var(--ggui-color-onSurface)'
                    : '1px solid var(--ggui-color-outlineVariant)',
                  cursor: 'pointer',
                  padding: 'var(--ggui-spacing-1)'
                }}
              >
                <Box style={{ position: 'relative', height: '100%' }}>
                  <Text style={{ fontSize: '10px', lineHeight: '1', fontWeight: 'bold', position: 'absolute', top: 0, left: 0 }}>{el.atomicNumber}</Text>
                  <div style={{ display: 'flex', alignItems: 'center', justifyContent: 'center', height: '100%' }}>
                    <Heading level={6} style={{ fontSize: '18px' }}>{el.symbol}</Heading>
                  </div>
                </Box>
              </Card>
            );
          })}
        </Box>

        {selectedElement && (
          <Card padding={24} style={{ border: `2px solid ${getCategoryColor(selectedElement.category)}` }}>
            <Stack direction="horizontal" gap={32} align="center" justify="between" aria-live="polite">
              <Stack gap={4}>
                <Heading level={2}>{selectedElement.name}</Heading>
                <Badge variant="secondary" pill>{selectedElement.category}</Badge>
              </Stack>
              <Stack direction="horizontal" gap={24}>
                <Stack gap={4}>
                  <Text variant="caption" color="var(--ggui-color-onSurfaceVariant)">Atomic No.</Text>
                  <Text variant="bodyLarge" style={{ fontWeight: 'var(--ggui-font-weight-bold)' }}>{selectedElement.atomicNumber}</Text>
                </Stack>
                <Stack gap={4}>
                  <Text variant="caption" color="var(--ggui-color-onSurfaceVariant)">Atomic Wt.</Text>
                  <Text variant="bodyLarge" style={{ fontWeight: 'var(--ggui-font-weight-bold)' }}>{selectedElement.atomicWeight}</Text>
                </Stack>
              </Stack>
              <Button size="sm" variant="outline" onClick={() => setSelectedElement(null)}>Close</Button>
            </Stack>
          </Card>
        )}
      </Stack>
    </Container>
  );
}

