import React, { useState, useEffect, useMemo, useCallback, useRef } from 'react';
import { Container, Card, Stack, Row, Box, Divider, Spacer, Text, Heading, Button, Input, TextArea, Select, Checkbox, Toggle, RadioGroup, Slider, Badge, Spinner, Avatar, Alert, Progress, Image, Icon, Link, Tooltip, Table, Tabs, Toast, Accordion } from '@ggui-ai/design/primitives';
import { SearchField, FormField, MenuItem, Tag, Dropdown, Autocomplete, Breadcrumb, Pagination } from '@ggui-ai/design/components';
import { Header, Sidebar, CardGrid, CommentThread, DataTable, ChatWindow, NavigationBar, FileUploader, UserProfileCard, NotificationCenter, Modal, CommandPalette, Footer, Hero } from '@ggui-ai/design/compositions';
import { Clickable, Hoverable, Pressable } from '@ggui-ai/design/interact';

// ⚠️ DO NOT EDIT — generated from data contract. Changing this will fail validation.
interface Props {
  product: { id: string; name: string; price: number; currency: string; rating: number; reviewCount: number; stock: number; description: string; specifications: unknown[]; reviews: unknown[] }; // Product object with id, name, price, currency, rating, stock, description, specifications[], reviews[]
  onAddToCart?: (data: Record<string, unknown>) => void; // Action: Add to Cart
}

function useComponent(props: Props) {
  const handleAddToCart = useCallback((data: Record<string, unknown>) => {
    props.onAddToCart?.(data);
  }, [props.onAddToCart]);

  const [quantity, setQuantity] = useState(1);
  const [activeTab, setActiveTab] = useState('description');

  const increment = () => setQuantity(prev => Math.min(prev + 1, props.product.stock));
  const decrement = () => setQuantity(prev => Math.max(prev - 1, 1));

  const isOutOfStock = props.product.stock === 0;
  const stockStatus = isOutOfStock ? 'Out of Stock' : props.product.stock < 5 ? 'Low Stock' : 'In Stock';

  return {
    quantity,
    activeTab,
    setActiveTab,
    increment,
    decrement,
    handleAddToCart,
    isOutOfStock,
    stockStatus
  };
}

export default function Component(props: Props) {
  const state = useComponent(props);
  const { product } = props;

  return (
    <Container maxWidth="xl" padding={24}>
      <Stack gap={32}>
        <Row gap={24} wrap>
          <Box background="var(--ggui-color-surfaceVariant, #f4f4f5)" borderRadius={16} padding={48} style={{ flex: 1, minWidth: 300, display: 'flex', alignItems: 'center', justifyContent: 'center' }}>
            <Heading level={2}>{product.name}</Heading>
          </Box>
          <Stack gap={16} style={{ flex: 1, minWidth: 300 }}>
            <Heading level={1}>{product.name}</Heading>
            <Text variant="bodyLarge" weight="bold">{product.currency}{product.price.toFixed(2)}</Text>
            <Row gap={4} align="center">
              {[...Array(5)].map((_, i) => (
                <Icon key={i} size={16} color={i < Math.floor(product.rating) ? 'var(--ggui-color-warning-500, #f59e0b)' : 'var(--ggui-color-outline, #d4d4d8)'}>
                  <svg viewBox="0 0 24 24" fill="currentColor" stroke="currentColor" strokeWidth="2" strokeLinecap="round" strokeLinejoin="round"><polygon points="12 2 15.09 8.26 22 9.27 17 14.14 18.18 21.02 12 17.77 5.82 21.02 7 14.14 2 9.27 8.91 8.26 12 2"/></svg>
                </Icon>
              ))}
              <Text variant="caption">({product.reviewCount} reviews)</Text>
            </Row>
            <Badge variant={product.stock === 0 ? 'error' : product.stock < 5 ? 'warning' : 'success'}>{state.stockStatus}</Badge>
            <Stack direction="horizontal" gap={8} align="center">
              <Button variant="secondary" size="sm" onClick={state.decrement} disabled={state.quantity <= 1} aria-label="Decrease quantity">-</Button>
              <Text>{state.quantity}</Text>
              <Button variant="secondary" size="sm" onClick={state.increment} disabled={state.quantity >= product.stock} aria-label="Increase quantity">+</Button>
              <Button variant="primary" disabled={state.isOutOfStock} onClick={() => state.handleAddToCart({ productId: product.id, quantity: state.quantity })}>Add to Cart</Button>
            </Stack>
          </Stack>
        </Row>
        <Tabs 
          activeKey={state.activeTab} 
          onChange={state.setActiveTab}
          items={[
            { key: 'description', label: 'Description', content: <Text>{product.description}</Text> },
            { key: 'specifications', label: 'Specifications', content: <DataTable columns={[{key: 'name', header: 'Property'}, {key: 'value', header: 'Value'}]} data={product.specifications as any[]} rowKey="name" /> },
            { key: 'reviews', label: 'Reviews', content: <CommentThread comments={product.reviews as any[]} onAddComment={() => {}} onReply={() => {}} onReaction={() => {}} /> }
          ]}
        />
      </Stack>
    </Container>
  );
}

// ⚠️ DO NOT EDIT imports — all available components are pre-imported.
import React, { useState, useEffect, useMemo, useCallback, useRef } from 'react';
import { Container, Card, Stack, Row, Box, Text, Heading, Button, Input, Select, Toggle, Progress, Avatar, Spacer } from '@ggui-ai/design/primitives';
import { FormField, Tag } from '@ggui-ai/design/components';

// ⚠️ DO NOT EDIT — generated from data contract. Changing this will fail validation.
interface Props {
  initialProfile: { name: string; email: string; avatar: string; role: string; emailNotifications: boolean; theme: 'light' | 'dark' };
  avatarOptions: string[]; // Available avatar emojis to choose from
  roleOptions: string[]; // Available role options for the dropdown
  onComplete?: (data: Record<string, unknown>) => void; // Action: Complete Setup
}

function useComponent(props: Props) {
  const handleComplete = useCallback((data: Record<string, unknown>) => {
    props.onComplete?.(data);
  }, [props.onComplete]);

  const [currentStep, setCurrentStep] = useState(1);
  const [formData, setFormData] = useState(props.initialProfile);

  const isStep1Valid = useMemo(() => {
    return formData?.name?.trim().length > 0 && /^[^\s@]+@[^\s@]+\.[^\s@]+$/.test(formData.email);
  }, [formData.name, formData.email]);

  useEffect(() => {
    if (props.initialProfile) setFormData(props.initialProfile);
  }, [props.initialProfile]);

  const handleNext = () => setCurrentStep(prev => Math.min(prev + 1, 3));
  const handleBack = () => setCurrentStep(prev => Math.max(prev - 1, 1));
  const updateField = (key: string, value: any) => setFormData(prev => ({ ...prev, [key]: value }));

  return { currentStep, formData, isStep1Valid, handleNext, handleBack, updateField, handleComplete };
}

export default function Component(props: Props) {
  const { currentStep, formData, isStep1Valid, handleNext, handleBack, updateField, handleComplete } = useComponent(props);

  return (
    <Container maxWidth="sm" padding={24}>
      <Stack gap={16}>
        <Heading level={2}>Onboarding - Step {currentStep} of 3</Heading>
        <Progress value={(currentStep / 3) * 100} size="md" />
        <Box paddingY={24} style={{ minHeight: 400 }}>
          {currentStep === 1 && (
            <Stack gap={16}>
              <FormField label="Name" required><Input value={formData.name} placeholder="Enter your full name" onChange={(v) => updateField('name', v)} /></FormField>
              <FormField label="Email" required><Input type="email" value={formData.email} placeholder="you@example.com" onChange={(v) => updateField('email', v)} /></FormField>
              <Stack gap={8}>
                <Text variant="label">Select Avatar</Text>
                <Stack direction="horizontal" gap={8}>
                  {props.avatarOptions.map(a => (
                    <Box
                      as="div"
                      key={a}
                    >
                      <Button variant={formData.avatar === a ? 'primary' : 'secondary'} size="sm" onClick={() => updateField('avatar', a)}>
                        {a}
                      </Button>
                    </Box>
                  ))}
                </Stack>
              </Stack>
            </Stack>
          )}
          {currentStep === 2 && (
            <Stack gap={16}>
              <FormField label="Role"><Select value={formData.role} options={props.roleOptions.map(r => ({ value: r, label: r }))} onChange={(v) => updateField('role', v)} /></FormField>
              <Toggle label="Email Notifications" checked={formData.emailNotifications} onChange={(v) => updateField('emailNotifications', v)} />
              <Toggle label="Dark Theme" checked={formData.theme === 'dark'} onChange={(v) => updateField('theme', v ? 'dark' : 'light')} />
            </Stack>
          )}
          {currentStep === 3 && (
            <Stack gap={8}>
              <Heading level={4}>Review</Heading>
              <Card padding={24} shadow="md">
                <Stack gap={12}>
                  <Text variant="bodySmall"><strong>Name:</strong> {formData.name}</Text>
                  <Text variant="bodySmall"><strong>Email:</strong> {formData.email}</Text>
                  <Text variant="bodySmall"><strong>Role:</strong> {formData.role || 'N/A'}</Text>
                  <Text variant="bodySmall"><strong>Notifications:</strong> <Tag variant={formData.emailNotifications ? 'success' : 'secondary'}>{formData.emailNotifications ? 'Enabled' : 'Disabled'}</Tag></Text>
                  <Text variant="bodySmall"><strong>Theme:</strong> {formData.theme === 'dark' ? 'Dark Mode' : 'Light Mode'}</Text>
                </Stack>
              </Card>
            </Stack>
          )}
        </Box>
        <Row justify="between">
          <Button variant="secondary" disabled={currentStep === 1} onClick={handleBack}>Back</Button>
          {currentStep < 3 ? <Button disabled={currentStep === 1 && !isStep1Valid} onClick={handleNext}>Next</Button> : <Button variant="primary" onClick={() => handleComplete(formData)}>Complete Setup</Button>}
        </Row>
      </Stack>
    </Container>
  );
}
